from cryptography.hazmat.primitives.serialization import load_ssh_private_key

def load_key(data: bytes, password: bytes | None):
    """
    Loads an OpenSSH private key from data, handling cryptography v43 
    TypeError constraints regarding unencrypted/encrypted key-password mismatches.
    """
    try:
        # Attempt to load with the provided password (or None)
        return load_ssh_private_key(data, password=password)
    except TypeError:
        if password is not None:
            # Per v43: TypeError is raised if an unencrypted key is given a password.
            # If this happens, the key is unencrypted; retry without a password.
            return load_ssh_private_key(data, password=None)
        else:
            # Per v43: TypeError is raised if an encrypted key is given no password.
            # We cannot decrypt it, so we raise a descriptive ValueError to avoid TypeError.
            raise ValueError("The key is encrypted and requires a password.")
