class PsList(interfaces.plugins.PluginInterface):
    @classmethod
    def get_requirements(cls):
        return [
            requirements.Layer(),
            requirements.SymbolTable()
        ]

    def run(self, logger):
        grid = TreeGrid(columns=[
            ('PID', 'int', 'PID'),
            ('Name', 'str', 'Name'),
            ('Offset', 'str', 'Offset')
        ])

        # Iterating through processes provided by the translation layer
        for process in self.layer.processes():
            grid.add_row([
                process.pid,
                process.name,
                hex(process.offset)
            ])

